#!/usr/bin/perl

use strict;
use warnings;

my %frequency;
my @words = split /\s+/, $ARGV[0];

foreach my $word (@words) {
    next unless defined $word && length $word; # Skip empty words or undefined values.
    $word = lc($word); # Convert to lowercase for case-insensitivity.

    if (exists $frequency{$word}) {
        $frequency{$word}++;
    } else {
        $frequency{$word} = 1;
    }
}

my @sorted_words = sort { $frequency{$b} <=> $frequency{$a} } keys %frequency;

foreach my $i (0..2) {
    last unless defined $sorted_words[$i];
    print "$sorted_words[$i]: $frequency{$sorted_words[$i]}";
}

#!/usr/bin/perl

use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Cannot open file: $!";
while (my $row = <$fh>) {
    chomp $row;
    next unless $row =~ /^(.+),(\d+),(.+)$/; # Skip rows that don't match the format
    if ($2 > 30) { # Check if age is greater than 30
        print "$row\n"; # Print row in original format, one per line
    }
}
close $fh;

