use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Cannot open file: $!";
while (my $line = <$fh>) {
    while ($line =~ /(\b[A-Z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,15}\b)/g) {
        print "$_\n";
    }
}
